void Parser::expr() {
	expratom();
	while( FIRST_binop(la.d_type) || la.d_type == Tok_Qmark || la.d_type == Tok_tick ) {
		if( FIRST_binop(la.d_type) ) {
			binop();
			expratom();
		} else if( la.d_type == Tok_Qmark ) {
			expect(Tok_Qmark, false, "expr");
			pattern();
		} else if( la.d_type == Tok_tick ) {
			expect(Tok_tick, false, "expr");
			exprCont();
		} else
			invalid("expr");
	}
}

