void Parser::exprCont() {
	if( la.d_type == Tok_Qmark ) {
		expect(Tok_Qmark, false, "exprCont");
		pattern();
	} else if( la.d_type == Tok_Amp || la.d_type == Tok_Bang || la.d_type == Tok_Lt || la.d_type == Tok_Gt || la.d_type == Tok_Eq || la.d_type == Tok_Lbrack || la.d_type == Tok_Rbrack || la.d_type == Tok_Plus || la.d_type == Tok_Minus || la.d_type == Tok_Star || la.d_type == Tok_Slash || la.d_type == Tok_bslash || la.d_type == Tok_Hash || la.d_type == Tok_5f ) {
		if( la.d_type == Tok_Amp ) {
			expect(Tok_Amp, false, "exprCont");
		} else if( la.d_type == Tok_Bang ) {
			expect(Tok_Bang, false, "exprCont");
		} else if( la.d_type == Tok_Lt ) {
			expect(Tok_Lt, false, "exprCont");
		} else if( la.d_type == Tok_Gt ) {
			expect(Tok_Gt, false, "exprCont");
		} else if( la.d_type == Tok_Eq ) {
			expect(Tok_Eq, false, "exprCont");
		} else if( la.d_type == Tok_Lbrack ) {
			expect(Tok_Lbrack, false, "exprCont");
		} else if( la.d_type == Tok_Rbrack ) {
			expect(Tok_Rbrack, false, "exprCont");
		} else if( la.d_type == Tok_Plus ) {
			expect(Tok_Plus, false, "exprCont");
		} else if( la.d_type == Tok_Minus ) {
			expect(Tok_Minus, false, "exprCont");
		} else if( la.d_type == Tok_Star ) {
			expect(Tok_Star, false, "exprCont");
		} else if( la.d_type == Tok_Slash ) {
			expect(Tok_Slash, false, "exprCont");
		} else if( la.d_type == Tok_bslash ) {
			expect(Tok_bslash, false, "exprCont");
		} else if( la.d_type == Tok_Hash ) {
			expect(Tok_Hash, false, "exprCont");
		} else if( la.d_type == Tok_5f ) {
			expect(Tok_5f, false, "exprCont");
		} else
			invalid("exprCont");
		expratom();
	} else
		invalid("exprCont");
}

